#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 1e4+5;
int T,n,sg[N],sum,cnt,a,b,c;
bool vis[N];
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void init_SG(){
    sg[0]=0;
    for(int i=1;i<=100;i++){
        memset(vis,0,sizeof(vis));
        for(int j=0;j<i;j++)
            for(int k=0;k<=j;k++)vis[sg[j]^sg[k]]=1;
        for(int j=0;j<=500;j++)
            if(!vis[j]){sg[i]=j;break;}
    }
}
int main(){
    init_SG();
    T=read();
    while(T--){
        n=read();sum=0;
        for(int i=n-1;i>=0;i--){
            int x=read();
            if(x&1)sum^=sg[i];
        }
        if(!sum){
            cout<<"-1 -1 -1\n0\n";
            continue;
        }
        cnt=0;
        for(int i=n-1;i>=0;i--)
            for(int j=i-1;j>=0;j--)
                for(int k=j;k>=0;k--){
                    int now=sum^sg[i]^sg[j]^sg[k];
                    if(now)continue;
                    if(!cnt)a=n-1-i,b=n-1-j,c=n-1-k;
                    ++cnt;
                }
        cout<<a<<" "<<b<<" "<<c<<"\n"<<cnt<<"\n";
    }
    return 0;
}
